FINAL_ANSWER: import random

def generate_test_case(N, M, K):
    board = [[random.randint(0, 9) for _ in range(M)] for _ in range(N)]
    stamps = []
    for _ in range(20):
        stamp = [[random.randint(0, 9) for _ in range(3)] for _ in range(3)]
        stamps.append(stamp)
    return N, M, K, board, stamps

def verify_output(L, K, results, N, M):
    if L > K: return False
    for m, i, j in results:
        if not (0 <= m < len(stamps) < 20 and 0 <= i <= N-3 and 0 <= j <= M-3):
            return False
    return True

# Example usage
N, M, K = 9, 9, 5
N, M, K, board, stamps = generate_test_case(N, M, K)
print(f'N={N}, M={M}, K={K}')
for row in board: print(row)
for s in stamps: 
    for r in s: print(r)
    print()
